import React, { Component } from 'react'
// import { Menu, Button } from 'antd'
import { Menu } from 'antd'
import {
  AppstoreOutlined,
  // MenuUnfoldOutlined,
  // MenuFoldOutlined,
  PieChartOutlined,
  DesktopOutlined,
  ContainerOutlined,
  // MailOutlined,
} from '@ant-design/icons'
import homeCss from './index.module.scss'

const { SubMenu } = Menu

export default class index extends Component {
  state = {
    collapsed: false,
  }
  render() {
    console.log(this.props)
    return (
      <div className={homeCss.home}>
        <div className={homeCss.left}>
          <Menu defaultSelectedKeys={['1']}
                defaultOpenKeys={['sub1']}
                mode="inline"
                theme="dark"
                inlineCollapsed={this.state.collapsed}>
            <Menu.Item key="1" icon={<PieChartOutlined />}>地盘</Menu.Item>
            <Menu.Item key="2" icon={<DesktopOutlined />}>项目集</Menu.Item>
            <Menu.Item key="3" icon={<ContainerOutlined />}>产品</Menu.Item>
            <Menu.Item key="4" icon={<ContainerOutlined />}>项目</Menu.Item>
            <Menu.Item key="5" icon={<ContainerOutlined />}>执行</Menu.Item>
            <Menu.Item key="6" icon={<ContainerOutlined />}>统计</Menu.Item>
            <SubMenu key="sub2" icon={<AppstoreOutlined />} title="测试">
              <Menu.Item key="7">测试1</Menu.Item>
              <Menu.Item key="8">测试2</Menu.Item>
              <SubMenu key="sub3" title="测试3">
                <Menu.Item key="9">测试3-1</Menu.Item>
                <Menu.Item key="10">测试3-2</Menu.Item>
              </SubMenu>
            </SubMenu>
          </Menu>
        </div>
        <div className={homeCss.right}>
          <div className="top"></div>
        </div>
      </div>
    )
  }
}
