import { Redirect } from 'react-router-dom'
import Login from '../component/login'
import Mission from '../component/mission'
import NotFount from '../component/NotFound'
import Home from '../component/home'

const routes = [
  {
    path: '/',
    exact: true,
    // component: Login,
    render: () => <Redirect to="/login"></Redirect>,
    requiresAuth: false,
    pageTitle: '登录页'
  },
  {
    path: '/login',
    component: Login,
    requiresAuth: false,
    pageTitle: '登录页'
    /* 子路由 */
    // routes: [
    //   {
    //     path: '/login',
    //     component: Log
    //   }
    // ]
  },
  {
    path: '/mission',
    component: Mission,
    requiresAuth: true,
    pageTitle: '任务'
  },
  {
    path: '/home',
    component: Home,
    requiresAuth: true,
    pageTitle: '主页'
  },
  {
    path: '*',
    component: NotFount,
    requiresAuth: true,
    pageTitle: '404'
  }
]

export default routes