import React, { Component } from 'react'
import route from './index'
import { Route, Redirect } from 'react-router-dom'


/**
 *未登录情况下，访问不需要权限校验的合法页面：允许访问
 *登陆情况下，访问登陆页面：禁止访问，跳转至主页
 *登陆情况下，访问除登陆页以外的合法页面：允许访问
 *登陆情况下，访问所有的非法页面：禁止访问，跳转至 404
 *未登录情况下，访问需要权限校验的页面：禁止访问，跳转至登陆页
 *未登录情况下，访问所有的非法页面：禁止访问，跳转至 404
 * @export
 * @class routerInterceptor
 * @extends {Component}
 */
export default class routerInterceptor extends Component {
  render() {
    /* 获取当前路由地址 */
    const { pathname } = this.props.location
    let router = route.find(path => path.path === pathname)
    if (!router) {
      router = route[route.length - 1]
    }
    console.log(this.props)
    const { changeTitle } = this.props
    const requiresAuth = router?.requiresAuth
    const token = window.localStorage.getItem('token') || window.sessionStorage.getItem('token') || ''

    /* 未登录 */
    if (!token) {
      if (!requiresAuth && router) {
        if (router.path === '/') {
          return <Redirect to="/login"></Redirect>
        } else {
          changeTitle('ZWC-Program-' + router.pageTitle)
          return <Route component={ router.component }></Route>
        }
      }
      return <Redirect to="/login"></Redirect>
    } else {
      if (router) {
        changeTitle('ZWC-Program-' + router.pageTitle)
        return <Route component={ router.component }></Route>
      }
      return <Redirect to="/404"></Redirect>
    }
  }
}

