import React, { Component } from 'react'
import { Input, Space, Checkbox, Button, message } from 'antd'
import { SketchOutlined, UserOutlined, EyeInvisibleOutlined, EyeTwoTone } from '@ant-design/icons'
import 'antd/dist/antd.css'
import loginCss from './index.module.scss'
// import componay from './company.jpg'

class index extends Component {
  state = {
    userName: 'zhouwuchao',
    passwd: '123456',
    checked: false
  }
  token = 'emhvdXd1Y2hhbzEyMzQ1Ng=='
  // formItemLayout = {
  //   labelCol: {
  //     xs: { span: 24 },
  //     sm: { span: 8 },
  //   },
  //   wrapperCol: {
  //     xs: { span: 24 },
  //     sm: { span: 16 },
  //   }
  // }
  render() {
    return (
      <div className={ loginCss.login }>
        <div className={ loginCss.loginDialog }>
          <div className={ loginCss.top }>
            <div className={ loginCss.left }>
              <h1 className={ loginCss.h1 }>ZWC项目管理系统</h1>
            </div>
          </div>
          <div className={ loginCss.bottom }>
            <div className={ loginCss.left }>
              <img src={ process.env.PUBLIC_URL + "/img/company.jpg" } alt="company LOGO" />
            </div>
            <div className={ loginCss.right }>
              <div>
                <span className={ loginCss.span1 }>用户名</span>
                <Input
                  size="large"
                  placeholder="请输入用户名"
                  style={{width: '250px'}}
                  value={this.state.userName}
                  onChange={evn => {this.getUserInfo(evn, 'userName')}}
                  prefix={<UserOutlined style={{color: '#0f71ee'}}/>} />
              </div>
              <div>
                <span className={ loginCss.span2 }>密码</span>
                <Space direction="vertical">
                  <Input.Password
                    placeholder="请输入密码"
                    size="large"
                    value={this.state.passwd}
                    style={{width: '250px'}}
                    prefix={<SketchOutlined style={{color: '#0f71ee'}}/>}
                    onChange={evn => {this.getUserInfo(evn, 'passwd')}}
                    iconRender={visible => (visible ? <EyeTwoTone /> : <EyeInvisibleOutlined />)}
                  />
                </Space>
                <Checkbox
                  checked={this.state.checked}
                  onChange={ evn => { this.onChange(evn) }}
                  style={{ marginLeft: '75px', marginTop: '20px' }}>保持登录</Checkbox>
                <Button type="primary" style={{display: "block", marginLeft: '75px', marginTop: '20px'}} onClick={() => {this.userLogin()}}>登录</Button>
              </div>
            </div>
          </div>
        </div>
      </div>
    )
  }
  getUserInfo(evn, type) {
    this.setState({
      [type]: evn.target.value
    })
  }
  onChange(evn) {
    this.setState({
      checked: evn.target.checked
    })
  }
  userLogin() {
    console.log(this.props)
    console.log(this.state)
    // if (this.)
    const { userName, passwd } = this.state
    if (userName && passwd) {
      if (window.btoa(window.encodeURIComponent(userName + passwd)) === this.token) {
        window.sessionStorage.setItem('token', window.btoa(window.encodeURIComponent(userName + passwd)))
        this.props.history.push({
          pathname: '/home'
        })
      } else {
        message.warning('用户名或者密码有错！')
      }
    } else {
      message.warning('请输入用户名或者密码！')
    }
    // if (userName === 'zhouwuchao' && passwd === '123456') {
    //   window.sessionStorage.setItem('token', window.btoa(window.encodeURIComponent(userName + passwd)))
    //   this.props.history.push({
    //     pathname: '/home'
    //   })
    // }
  }
  componentDidMount() {
    // let str = '好好学习，天天向上'
    // console.log(window.btoa(window.encodeURIComponent(str)))
  }
}

export default index